#include <stdio.h>
#include <string.h>
int main() {
    char s[101];
    scanf("%s", s);
    if (s[0] >= 'A' && s[0] <= 'Z' && strlen(s) > 1) {
        int allLower = 1;
        for (int i = 1; i < strlen(s); i++) {
            if (s[i] < 'a' || s[i] > 'z') {
                allLower = 0;
                break;
            }
        }
        if (allLower) {
            for (int i = 0; i < strlen(s); i++) {
                s[i] = toupper(s[i]);
            }
        }
    } else if (strlen(s) > 1) {
        int allUpper = 1;
        for (int i = 0; i < strlen(s); i++) {
            if (s[i] < 'A' || s[i] > 'Z') {
                allUpper = 0;
                break;
            }
        }
        if (allUpper) {
            for (int i = 0; i < strlen(s); i++) {
                s[i] = tolower(s[i]);
            }
        }
    }
    printf("%s\n", s);
    return 0;
}

